### 命令（Commands）

创建一个命令，授予用户特定角色的所有权限（GrantUserRoleCommand）：

```csharp
public class GrantUserRoleCommand : IRequest<User>
{
    public Guid UserId { get; set; }
    public Guid RoleId { get; set; }
}
```

创建一个处理 GrantUserRoleCommand 的处理程序（GrantUserRoleHandler）：

```csharp
public class GrantUserRoleHandler : IRequestHandler<GrantUserRoleCommand, User>
{
    // 在这里注入您的数据存储，例如数据库上下文
    // private readonly YourDbContext _context;

    public GrantUserRoleHandler(/*YourDbContext context*/)
    {
        // _context = context;
    }

    public async Task<User> Handle(GrantUserRoleCommand request, CancellationToken cancellationToken)
    {
        // 从数据库获取用户和角色
        // var user = await _context.Users.Include(u => u.Roles)
        //     .SingleOrDefaultAsync(u => u.Id == request.UserId, cancellationToken);
        // var role = await _context.Roles.SingleOrDefaultAsync(r => r.Id == request.RoleId, cancellationToken);

        // 示例user 和 role（硬编码）
        var user = new User
        {
            Id = Guid.NewGuid(),
            UserName = "admin",
            Roles = new List<Role>()
        };

        var role = new Role
        {
            Id = Guid.NewGuid(),
            Name = "administrator",
            Permissions = new List<Permission>
            {
                new Permission { Id = Guid.NewGuid(), Name = "MenuA" },
                new Permission { Id = Guid.NewGuid(), Name = "MenuB" }
            }
        };

        // 将角色添加到用户角色列表并保存
        user.Roles.Add(role);

        // 在实际使用中，保存到数据库：
        // _context.Users.Update(user);
        // await _context.SaveChangesAsync(cancellationToken);

        return user;
    }
